parameters.text:
=Customer Review Data:

Customer Name: {{ $json.customerName }}
Customer Email: {{ $json.customerEmail }}
Customer ID: {{ $json.customerId }}
Product/Service: {{ $json.product }}
Review Text: {{ $json.reviewText }}
Rating: {{ $json.rating }}/5

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "sentiment": {
      "type": "string",
      "enum": ["positive", "neutral", "negative"],
      "description": "Overall sentiment of the review"
    },
    "intent": {
      "type": "string",
      "enum": ["complaint", "praise", "query", "suggestion", "other"],
      "description": "Primary intent of the customer"
    },
    "suggestedReply": {
      "type": "string",
      "description": "Appropriate reply message for the customer"
    },
    "isVip": {
      "type": "boolean",
      "description": "Whether this is a VIP customer"
    },
    "urgency": {
      "type": "string",
      "enum": ["low", "medium", "high", "critical"],
      "description": "Urgency level of the issue"
    },
    "keyIssues": {
      "type": "array",
      "items": {"type": "string"},
      "description": "List of key issues or topics mentioned"
    }
  },
  "required": ["sentiment", "intent", "suggestedReply", "isVip", "urgency"]
}

parameters.text:
=🚨 *Negative Review Alert - {{ $('Workflow Configuration').first().json.isVip ? "VIP CUSTOMER" : "Customer" }}*

*Customer:* {{ $('Workflow Configuration').first().json.customerName }} ({{ $('Workflow Configuration').first().json.customerEmail }})
*Product:* {{ $('Workflow Configuration').first().json.product }}
*Rating:* {{ $('Workflow Configuration').first().json.rating }}/5 ⭐
*Urgency:* {{ $json.urgency.toUpperCase() }}
*Intent:* {{ $json.intent }}

*Review:*
{{ $('Workflow Configuration').first().json.reviewText }}

*Key Issues:*
{{ $json.keyIssues ? $json.keyIssues.map(issue => `• ${issue}`).join("\n") : "None identified" }}

*Support Ticket:* #{{ $json.id || "Created" }}
*Status:* Escalated to support team

parameters.responseBody:
={
  "status": "escalated",
  "message": "Your feedback has been received and escalated to our support team. We will contact you shortly.",
  "ticketId": "={{ $('Create CRM Support Ticket').first().json.id }}",
  "priority": "={{ $('Analyze Review Sentiment').first().json.urgency }}"
}
